const body = $input.first().json.body || {};
const action = String(body.action || '').trim();

// Ping для health-check со страницы платформы
if (action === 'ping' || body.message === 'ping') {
  return [{ json: { valid: 0, error: 'pong', action: 'ping' } }];
}

const ALLOWED = ['register', 'login', 'logout', 'verify', 'change_password'];
if (!ALLOWED.includes(action)) {
  return [{ json: { valid: 0, error: 'Неизвестный action: ' + action } }];
}

// Валидация username (для register/login)
function validateUsername(s) {
  const u = String(s || '').trim();
  if (!u) return { ok: false, error: 'Логин обязателен' };
  if (u.length < 2) return { ok: false, error: 'Логин слишком короткий (минимум 2 символа)' };
  if (u.length > 100) return { ok: false, error: 'Логин слишком длинный (максимум 100 символов)' };
  if (!/^[A-Za-zА-Яа-яЁё0-9_\-. ]+$/.test(u)) {
    return { ok: false, error: 'Логин: разрешены буквы, цифры, пробел, _ - .' };
  }
  const RESERVED = ['system', 'admin', 'root', 'null', 'undefined', 'anonymous'];
  if (RESERVED.includes(u.toLowerCase())) {
    return { ok: false, error: 'Это имя зарезервировано системой' };
  }
  return { ok: true, value: u };
}

// Валидация пароля
function validatePassword(s, label) {
  label = label || 'Пароль';
  const p = String(s || '');
  if (!p) return { ok: false, error: label + ' обязателен' };
  if (p.length < 6) return { ok: false, error: label + ' слишком короткий (минимум 6 символов)' };
  if (p.length > 200) return { ok: false, error: label + ' слишком длинный (максимум 200 символов)' };
  return { ok: true, value: p };
}

// Валидация токена
function validateToken(s) {
  const t = String(s || '').trim();
  if (!t) return { ok: false, error: 'Токен обязателен' };
  if (!/^[a-f0-9]{64}$/.test(t)) return { ok: false, error: 'Неверный формат токена' };
  return { ok: true, value: t };
}

const out = { valid: 1, action };

if (action === 'register' || action === 'login') {
  const u = validateUsername(body.username);
  if (!u.ok) return [{ json: { valid: 0, error: u.error } }];
  const p = validatePassword(body.password);
  if (!p.ok) return [{ json: { valid: 0, error: p.error } }];
  out.username = u.value;
  out.password = p.value;
  if (action === 'login') {
    out.remember = !!body.remember;
    // Токен генерится в SQL через pgcrypto: encode(gen_random_bytes(32),'hex').
    // node-crypto в Code-ноде n8n запрещён по умолчанию (NODE_FUNCTION_ALLOW_BUILTIN).
    // expires_at: remember → 10 лет, иначе 24 часа
    const ms = out.remember ? (10 * 365 * 24 * 60 * 60 * 1000) : (24 * 60 * 60 * 1000);
    out.expires_at_ms = Date.now() + ms;
  }
}

if (action === 'logout' || action === 'verify') {
  const t = validateToken(body.token);
  if (!t.ok) return [{ json: { valid: 0, error: t.error } }];
  out.token = t.value;
}

if (action === 'change_password') {
  const t = validateToken(body.token);
  if (!t.ok) return [{ json: { valid: 0, error: t.error } }];
  const op = validatePassword(body.old_password, 'Текущий пароль');
  if (!op.ok) return [{ json: { valid: 0, error: op.error } }];
  const np = validatePassword(body.new_password, 'Новый пароль');
  if (!np.ok) return [{ json: { valid: 0, error: np.error } }];
  if (body.old_password === body.new_password) {
    return [{ json: { valid: 0, error: 'Новый пароль должен отличаться от текущего' } }];
  }
  out.token = t.value;
  out.old_password = op.value;
  out.new_password = np.value;
}

return [{ json: out }];

// Format register response. Если UNIQUE-нарушение на username — даём
// читаемое сообщение «логин занят» вместо технического Postgres-error.
const item = $input.first();
const data = item && item.json ? item.json : null;
if (!data || data.error) {
  const msg = data && data.error ? String(data.error.message || data.error) : 'Не удалось сохранить';
  if (/unique|duplicate|already exists/i.test(msg)) {
    return [{ json: { response: 'error', error: 'Этот логин уже занят' } }];
  }
  return [{ json: { response: 'error', error: 'Ошибка регистрации: ' + msg } }];
}
return [{ json: { response: 'ok', user_id: data.id, username: data.username } }];

// ГИБРИД-ЛОГИН (LDAP/login_work). Сначала проверяем ЛОКАЛЬНЫЙ пароль (быстро,
// работает офлайн для админа). Не подошёл — спрашиваем офисный сервис login_work
// (он сам ходит в домен). reload:true → пускаем; reload:false → неверный пароль;
// сервис недоступен → честная ошибка (НЕ выдаём за «неверный пароль»).
// АДРЕС СЕРВИСА — меняется здесь:
const LDAP_URL = 'http://130.100.92.170/login_work/';
const item = $input.first();
const data = item && item.json ? item.json : null;
const src = $('Валидация').first().json;
const base = { token: src.token, expires_at_ms: src.expires_at_ms, remember: src.remember, username: src.username };

// 1) Локальный пароль подошёл (есть строка из SQL: login verify)
if (data && data.id && !data.error) {
  return [{ json: Object.assign({}, base, { _skip_insert: false, _auth: 'local', user_id: data.id, display_name: '' }) }];
}

// Эвристика: вытаскиваем ФИО — первую строку из «Три Русских Слова» в ответе сервиса.
function findFio(o) {
  // Границы длины слов в regex (исключают патологические строки) + лимиты
  // глубины/бюджета обхода — защита от кривого/враждебного ответа сервиса.
  var RE = /^[А-ЯЁ][а-яё-]{1,40} +[А-ЯЁ][а-яё-]{1,40} +[А-ЯЁ][а-яё-]{1,40}$/;
  var f = '', budget = 5000;
  (function walk(v, depth) {
    if (f || budget <= 0 || depth > 6) return;
    budget--;
    if (typeof v === 'string') { if (v.length <= 200) { var t = v.trim(); if (RE.test(t)) f = t; } }
    else if (v && typeof v === 'object') { for (var k in v) { walk(v[k], depth + 1); if (f) return; } }
  })(o, 0);
  return f;
}

// 2) Локально не подошло → проверяем домен
let ans = null, neterr = false;
try {
  const formBody = 'data=' + encodeURIComponent(JSON.stringify({ prefix: 'user', action: 'create', prop: { username: src.username, password: src.password, id: 'null' } }));
  const resp = await this.helpers.httpRequest({ method: 'POST', url: LDAP_URL, headers: { 'Content-Type': 'application/x-www-form-urlencoded' }, body: formBody, timeout: 12000, json: false });
  ans = (typeof resp === 'string') ? JSON.parse(resp) : resp;
} catch (e) { neterr = true; }

if (neterr || !ans || typeof ans !== 'object') {
  return [{ json: { _skip_insert: true, response: 'error', error: 'Сервис аутентификации недоступен. Попробуйте позже или обратитесь к администратору.' } }];
}
if (ans.reload === true) {
  // _ldap_raw — сырой ответ сервиса (только в лог n8n, на фронт не уходит:
// Format login OK собирает ответ заново). Нужен, чтобы узнать, в каком
// поле сервис отдаёт ФИО (см. гайд, Приложение).
let raw = ''; try { raw = JSON.stringify(ans).slice(0, 2000); } catch (e) {}
return [{ json: Object.assign({}, base, { _skip_insert: false, _auth: 'ldap', user_id: null, display_name: findFio(ans), _ldap_raw: raw }) }];
}
return [{ json: { _skip_insert: true, response: 'error', error: 'Неверный логин или пароль' } }];

const item = $input.first();
const data = item && item.json ? item.json : null;
const prep = $('Login prep').first().json;
let dn = ''; try { dn = ($('SQL: ensure user').first().json.display_name) || ''; } catch (_) {}
if (!dn) dn = prep.display_name || '';
let un = prep.username; try { const eu = $('SQL: ensure user').first().json; if (eu && eu.username) un = eu.username; } catch (_) {}
if (!data || data.error || !data.token) {
  return [{ json: { response: 'error', error: 'Не удалось создать сессию: ' + (data && data.error ? (data.error.message || data.error) : 'неизвестная ошибка') } }];
}
return [{ json: { response: 'ok', token: data.token, user_id: data.user_id, username: un, display_name: dn, remember: prep.remember, expires_at_ms: prep.expires_at_ms } }];

// Идемпотентный logout: даже если токен уже удалён или не существовал —
// возвращаем ok. Юзер на фронте всё равно очищает localStorage.
return [{ json: { response: 'ok' } }];

const item = $input.first();
const data = item && item.json ? item.json : null;
// Сбой БД (Postgres-узел упал) НЕ выдаём за «невалидный токен» — иначе сбой БД
// разлогинивает всех. Фронт по db_unavailable не чистит сессию (транзиентно).
if (data && data.error) {
  return [{ json: { response: 'error', error: 'Сервис временно недоступен', db_unavailable: true } }];
}
if (!data || !data.user_id) {
  return [{ json: { response: 'error', error: 'Токен невалиден или истёк', auth_required: true } }];
}
return [{ json: {
  response: 'ok',
  user_id: data.user_id,
  username: data.username,
  display_name: data.display_name || null,
  is_admin: !!data.is_admin,
  expires_at: data.expires_at,
  remember: data.remember,
}}];

const item = $input.first();
const data = item && item.json ? item.json : null;
if (!data || data.error || !data.id) {
  // Пусто = либо токен невалиден, либо старый пароль не совпал.
  // Не разглашаем какое именно — единое сообщение.
  return [{ json: { response: 'error', error: 'Не удалось сменить пароль (проверь текущий пароль)' } }];
}
// Остальные сессии этого юзера УЖЕ инвалидированы в SQL (_revoke: DELETE
// auth_sessions ... token <> $1) — после смены пароля остаётся только текущая.
return [{ json: { response: 'ok' } }];
